const j=$('Assoc page 1').first().json||{};const ip=(((j.data||{}).boards||[])[0]||{}).items_page||{};const cur=ip.cursor||null;
const q=cur?('query { next_items_page(limit:500, cursor:"'+cur+'"){ cursor items { id name group { title } column_values(ids:[\"role8\",\"team\",\"client_name6\",\"status0\"]){ id text } } } }'):'query { complexity { query } }';
return [{json:{body: JSON.stringify({query:q})}}];

const j=$('Assoc page 2').first().json||{};const ip=(j.data||{}).next_items_page||{};const cur=ip.cursor||null;
const q=cur?('query { next_items_page(limit:500, cursor:"'+cur+'"){ cursor items { id name group { title } column_values(ids:[\"role8\",\"team\",\"client_name6\",\"status0\"]){ id text } } } }'):'query { complexity { query } }';
return [{json:{body: JSON.stringify({query:q})}}];

const j=$('Risks page 1').first().json||{};const ip=(((j.data||{}).boards||[])[0]||{}).items_page||{};const cur=ip.cursor||null;
const q=cur?('query { next_items_page(limit:500, cursor:"'+cur+'"){ cursor items { id name group { title } column_values { id text column { title } } } } }'):'query { complexity { query } }';
return [{json:{body: JSON.stringify({query:q})}}];

const org=$('Read accounts').all().map(r=>r.json);
const SQ=String.fromCharCode(39);const qq=s=>SQ+String(s).split(SQ).join(SQ+SQ)+SQ;
const col=(cv,id)=>{const c=(cv||[]).find(x=>x.id===id);return (c&&c.text)?c.text:null;};
const pageItems=(node,first)=>{try{const j=$(node).first().json||{};const d=j.data||{};const ip=first?((((d.boards||[])[0]||{}).items_page)||{}):(d.next_items_page||{});return Array.isArray(ip.items)?ip.items:[];}catch(e){return [];}};
const stmts=[];
// ── Associates (Assigned Associates 2.2 Live, 1118885420) - ALL pages, so counts are
// right (the old single 200-item query silently dropped ~80% of the board) ──
const asItems=[...pageItems('Assoc page 1',true),...pageItems('Assoc page 2',false),...pageItems('Assoc page 3',false)];
for(const it of asItems){const cv=it.column_values||[];const cname=col(cv,'client_name6')||'';const team=col(cv,'team');const placement=col(cv,'status0');
const acc=org.find(a=>a.name&&cname.toLowerCase().includes(String(a.name).toLowerCase()));const accId=acc?acc.id:null;
stmts.push('INSERT INTO associates (monday_item_id,name,account_id,account_name,project_or_programme,placement_status,last_verified) VALUES ('+qq(it.id)+','+qq(it.name)+','+(accId?qq(accId):'NULL')+','+qq(cname)+','+(team?qq(team):'NULL')+','+(placement?qq(placement):'NULL')+',now()) ON CONFLICT (monday_item_id) DO UPDATE SET account_id=EXCLUDED.account_id,account_name=EXCLUDED.account_name,project_or_programme=EXCLUDED.project_or_programme,placement_status=EXCLUDED.placement_status,last_verified=now();');}
// ── Risk register (Risks, Issues and Incidents, 1583443098) - columns matched by
// TITLE fragments (board column ids unknown; unmatched columns land in the run log) ──
const rkItems=[...pageItems('Risks page 1',true),...pageItems('Risks page 2',false)];
const byTitle=(it,frags)=>{for(const c of (it.column_values||[])){const t=((c.column&&c.column.title)||'').toLowerCase();if(!c.text)continue;for(const f of frags){if(t.includes(f))return c.text;}}return null;};
const rkCols=[...new Set(rkItems.flatMap(it=>(it.column_values||[]).map(c=>(c.column&&c.column.title)||'')))].filter(Boolean);
for(const it of rkItems){const acct=byTitle(it,['account','client','customer'])||((it.group&&it.group.title)||'');
const accRow=org.find(a=>a.name&&acct&&acct.toLowerCase().includes(a.name.toLowerCase()))||org.find(a=>a.name&&a.name.length>=4&&new RegExp('\\b'+a.name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'\\b','i').test(it.name||''))||null;
const v=x=>x?qq(x):'NULL';const ageTxt=byTitle(it,['ticket age']);const ageM=ageTxt?String(ageTxt).match(/\d+/):null;const ageN=ageM?parseInt(ageM[0],10):null;
stmts.push('INSERT INTO risks (monday_item_id,name,account_id,account_name,project_name,kind,likelihood,severity,impact_level,escalation,status,treatment_plan,responsible,age_days,last_verified) VALUES ('+qq(it.id)+','+qq(it.name||'')+','+(accRow?qq(accRow.id):'NULL')+','+v(acct)+','+v(byTitle(it,['project','sow']))+','+v(byTitle(it,['risk or issue','kind','type']))+','+v(byTitle(it,['likelihood','probability']))+','+v(byTitle(it,['severity']))+','+v(byTitle(it,['impact level']))+','+v(byTitle(it,['escalation']))+','+v(byTitle(it,['status']))+','+v(byTitle(it,['treatment','mitigation','action']))+','+v(byTitle(it,['responsible','owner','assigned']))+','+(ageN==null?'NULL':ageN)+',now()) ON CONFLICT (monday_item_id) DO UPDATE SET name=EXCLUDED.name,account_id=EXCLUDED.account_id,account_name=EXCLUDED.account_name,project_name=EXCLUDED.project_name,kind=EXCLUDED.kind,likelihood=EXCLUDED.likelihood,severity=EXCLUDED.severity,impact_level=EXCLUDED.impact_level,escalation=EXCLUDED.escalation,status=EXCLUDED.status,treatment_plan=EXCLUDED.treatment_plan,responsible=EXCLUDED.responsible,age_days=EXCLUDED.age_days,last_verified=now();');}
const sql=stmts.length?stmts.join(' '):'SELECT 1 AS noop;';
return [{json:{sql,associates:asItems.length,risks:rkItems.length,risk_board_columns:rkCols}}];
